    const stepId2 = toOptionalString2(baseTarget.stepId) ?? toOptionalString2(thread?.stepId);
    if (runId2 && stepId2) {
      attemptContext = selectAttemptDeliveryContextCtx(ctx, `a.run_id = ? and a.step_id = ?`, [runId2, stepId2]);
    }
