  const stepKey = toOptionalString2(baseTarget.stepKey) ?? toOptionalString2(thread?.stepKey) ?? toOptionalString2(message.stepKey) ?? toOptionalString2(attemptContext?.step_key) ?? null;
  const attemptId = toOptionalString2(baseTarget.attemptId) ?? toOptionalString2(message.attemptId) ?? toOptionalString2(thread?.attemptId) ?? toOptionalString2(attemptContext?.attempt_id) ?? null;
  const laneId = toOptionalString2(baseTarget.laneId) ?? toOptionalString2(thread?.laneId) ?? toOptionalString2(message.laneId) ?? toOptionalString2(attemptContext?.lane_id) ?? null;
  const sessionId = toOptionalString2(baseTarget.sessionId) ?? toOptionalString2(message.sourceSessionId) ?? toOptionalString2(thread?.sessionId) ?? toOptionalString2(attemptContext?.session_id) ?? null;
  const sessionStatusFromDb = toOptionalString2(attemptContext?.session_status)?.toLowerCase() ?? null;
  const trackedSessionStatus = sessionId ? toOptionalString2(getTrackedSessionState(ctx, sessionId)?.status)?.toLowerCase() ?? null : null;
  const sessionStatus = sessionStatusFromDb ?? trackedSessionStatus;
  const sessionToolType = toOptionalString2(attemptContext?.session_tool_type) ?? null;
  const executorKindRaw = toOptionalString2(attemptContext?.executor_kind);
  const executorKind = executorKindRaw === "unified" || executorKindRaw === "shell" || executorKindRaw === "manual" ? executorKindRaw : null;
